// ───────────────────────────────────────────────────────────
// TABLE NAME MANAGER v4.0
//
// Changes vs v3.2:
//  - Static data keyed by sessionId → no cross-user pollution
//  - Schema-prefix stripping (public.orders → orders)
//  - Common-word blocklist prevents "hello" being saved as table
//  - Emits same fields as before (backward-compat)
// ───────────────────────────────────────────────────────────

const staticData = $getWorkflowStaticData('global');
const sessionId  = ($input.first().json.sessionId ?? 'default').replace(/[^a-zA-Z0-9_-]/g, '_');
const userMessage = ($input.first().json.chatInput ?? '').trim();

// Per-session storage
if (!staticData.sessions) staticData.sessions = {};
if (!staticData.sessions[sessionId]) staticData.sessions[sessionId] = {};
const sess = staticData.sessions[sessionId];

// ── RESET ────────────────────────────────────────────────────
if (/^(reset|change|switch)\s+table$/i.test(userMessage)) {
  delete sess.tableName;
  return [{
    json: { chatInput: userMessage, tableName: null,
            justSetTable: false, isReset: true, sessionId }
  }];
}

// ── CAPTURE TABLE NAME ───────────────────────────────────────
// Strip optional schema prefix (public.my_table → my_table)
let candidate = userMessage;
const dotIdx = candidate.indexOf('.');
if (dotIdx !== -1) candidate = candidate.slice(dotIdx + 1);

const looksLikeIdentifier = /^[a-zA-Z_][a-zA-Z0-9_]{0,62}$/.test(candidate);

// Blocklist — common greetings that match the identifier pattern
const RESERVED = new Set([
  'hello','hi','hey','help','yes','no','ok','okay','thanks',
  'sure','start','begin','go','done','exit','quit','stop',
  'what','show','list','get','find','give','tell','run'
]);

let justSetTable = false;
if (!sess.tableName && looksLikeIdentifier && !RESERVED.has(candidate.toLowerCase())) {
  sess.tableName = candidate;   // store the clean (no-schema) name
  justSetTable = true;
}

return [{
  json: {
    chatInput:    userMessage,
    tableName:    sess.tableName ?? null,
    justSetTable,
    isReset:      false,
    sessionId
  }
}];

const tableCtx   = $('Manage Table Name').first().json;
const schemaRows = $input.all();
const staticData = $getWorkflowStaticData('global');

let columnList = '';
let validColumnNames = [];

if (schemaRows.length === 0 || !schemaRows[0].json.column_name) {
  columnList = `⚠️ Table "${tableCtx.tableName}" was not found in schema public.\nPlease check the table name and try again, or type \`reset table\` to start over.`;
  staticData.validColumns   = [];
  staticData.validTableName = null;
} else {
  const columns = schemaRows.map(row => ({
    name:     row.json.column_name,
    dtype:    row.json.data_type,
    nullable: row.json.is_nullable === 'YES' ? 'nullable' : 'NOT NULL',
    defVal:   row.json.column_default ? ` | default: ${row.json.column_default}` : '',
    isMoney:  row.json.data_type === 'money'
  }));

  validColumnNames = columns.map(c => c.name);
  staticData.validColumns    = validColumnNames;
  staticData.validTableName  = tableCtx.tableName;

  const truncated = schemaRows.length >= 120;
  columnList = columns
    .map(c => {
      const castHint = c.isMoney ? ' ⚠️ money→cast: col::numeric' : '';
      return `  - ${c.name.padEnd(28)} (${c.dtype}, ${c.nullable}${c.defVal}${castHint})`;
    })
    .join('\n');
  if (truncated) columnList += '\n  … (first 120 columns shown)';
}

// Build shorthand → exact column map
const suffixes = ['_eur','_usd','_gbp','_share','_growth','_index',
  '_price','_count','_total','_rate','_pct','_percent',
  '_avg','_sum','_min','_max','_id','_code','_name'];
const mappings = [];
for (const name of validColumnNames) {
  const n = name.toLowerCase();
  for (const suffix of suffixes) {
    if (n.endsWith(suffix)) {
      const shorthand = n.slice(0, n.length - suffix.length);
      if (shorthand.length > 1) {
        mappings.push(`  If user says "${shorthand}" → exact column: ${name}`);
      }
      break;
    }
  }
}
const conceptMap = mappings.length > 0
  ? mappings.join('\n')
  : '  (all column names are self-explanatory)';

return [{
  json: {
    chatInput:    tableCtx.chatInput,
    tableName:    tableCtx.tableName,
    justSetTable: tableCtx.justSetTable,
    isReset:      tableCtx.isReset,
    columnList,
    conceptMap
  }
}];
